import{_ as r,o as t,c as s,a2 as o}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Stratégie & Contenu","description":"","frontmatter":{"title":"Stratégie & Contenu"},"headers":[],"relativePath":"docs/fr/advertisers/sponsored-mail/design-guide/strategy.md","filePath":"docs/fr/advertisers/sponsored-mail/design-guide/strategy.md"}'),a={name:"docs/fr/advertisers/sponsored-mail/design-guide/strategy.md"};function i(d,e,p,l,n,u){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="definition-de-la-campagne" tabindex="-1">Définition de la campagne <a class="header-anchor" href="#definition-de-la-campagne" aria-label="Permalink to &quot;Définition de la campagne&quot;">​</a></h1><p>Une campagne d&#39;Asile Colis réussie repose sur trois piliers : une mécanique claire, une expérience fluide et une offre irrésistible.</p><hr class="my-6"><h2 class="text-blue-200 mb-4">1. La Mécanique</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:20px;margin-bottom:40px;width:100%;"><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;"><h3 class="mt-0 fs-4">🏷️ Promotion</h3><p class="mb-2 text-grey-dk-000"><em>&quot;Scannez pour obtenir une offre exclusive&quot;</em></p><p class="mb-0">Idéal pour la conversion immédiate en ligne.</p></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;background-color:#eff6ff;border-color:#2563eb;"><h3 class="mt-0 fs-4 text-purple-200">🏪 Drive to Store</h3><p class="mb-2 text-grey-dk-000"><em>&quot;Présentez cette carte en boutique pour un café offert&quot;</em></p><p class="mb-0">Générez du trafic physique ou proposez une mécanique hybride (Coupon valable Web + Magasin).</p></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;"><h3 class="mt-0 fs-4">📚 Contenu Éducatif</h3><p class="mb-2 text-grey-dk-000"><em>&quot;Scannez pour lire le rapport du GIEC&quot;</em></p><p class="mb-2 text-grey-dk-000"><em>&quot;Découvrez nos 5 recettes de saison&quot;</em></p><p class="mb-0">Pour l&#39;image de marque et l&#39;engagement.</p></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;"><h3 class="mt-0 fs-4">🎲 Jeux / Concours</h3><p class="mb-2 text-grey-dk-000"><em>&quot;Flashez pour tourner la roue&quot;</em></p><p class="mb-0">Idéal pour la collecte de leads.</p></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;"><h3 class="mt-0 fs-4">📱 Drive to App</h3><p class="mb-2 text-grey-dk-000"><em>&quot;Téléchargez l&#39;app pour débloquer vos points&quot;</em></p><p class="mb-0">Pour l&#39;acquisition d&#39;utilisateurs mobiles.</p></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;"><h3 class="mt-0 fs-4">⭐ Feedback</h3><p class="mb-2 text-grey-dk-000"><em>&quot;Donnez votre avis contre un cadeau&quot;</em></p><p class="mb-0">Pour enrichir la connaissance client.</p></div></div><h2 class="text-blue-200 mb-4">2. L&#39;Expérience</h2><div style="background-color:#f6f8fa;border-left:4px solid #2d6fd6;padding:20px;border-radius:4px;margin-bottom:40px;"><h3 class="mt-0 text-blue-200">📱 Pensez Mobile First</h3><p>L&#39;expérience post-scan se fait à 99% sur smartphone.</p><ul><li>Votre Landing Page <strong>doit</strong> être responsive.</li><li>Le temps de chargement doit être immédiat (3G/4G).</li><li>Le formulaire doit être court.</li></ul></div><h2 class="text-blue-200 mb-4">3. L&#39;Offre</h2><div style="display:flex;gap:20px;flex-wrap:wrap;"><div style="flex:1;border:1px solid #28a745;background-color:#f0fcf4;padding:20px;border-radius:8px;"><h3 class="mt-0 text-green-200">✅ Valeur Monétaire</h3><p class="fs-4 mb-0"><strong>&quot;10€ offerts&quot;</strong></p><p>Beaucoup plus concret et percutant qu&#39;un pourcentage.</p></div><div style="flex:1;border:1px solid #e1e4e8;background-color:#fff;padding:20px;border-radius:8px;"><h3 class="mt-0 text-grey-dk-000">🤔 Pourcentage</h3><p class="fs-4 mb-0">&quot;-10% de réduction&quot;</p><p>Souvent perçu comme une simple &quot;taxe en moins&quot;. Moins incitatif.</p></div><div style="flex:1;border:1px solid #28a745;background-color:#f0fcf4;padding:20px;border-radius:8px;"><h3 class="mt-0 text-green-200">🎁 Produit Offert</h3><p class="fs-4 mb-0"><strong>&quot;Votre accessoire offert&quot;</strong></p><p>Très fort levier psychologique (Cadeau vs Économie).</p></div></div>',9)])])}const f=r(a,[["render",i]]);export{m as __pageData,f as default};
